.container {
  overflow: hidden; /* creates BFC */
}

/* Modern way — no side effects */
.container {
  display: flow-root; /* creates BFC, that's its whole job */
}

/* Also creates BFC automatically */
.container {
  display: flex; /* or grid */
}

/* Physical properties — breaks in RTL */
.card {
  margin-left: 1rem;
  padding-right: 2rem;
  border-bottom: 1px solid;
  text-align: left;
}

/* Logical properties — works everywhere */
.card {
  margin-inline-start: 1rem;
  padding-inline-end: 2rem;
  border-block-end: 1px solid;
  text-align: start;
}

/* auto-fill */
grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));

/* auto-fit */
grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));

.card-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  /* Each card spans 3 rows */
  grid-template-rows: auto auto 1fr;
  gap: 1rem;
}

.card {
  display: grid;
  grid-row: span 3;
  /* Inherit parent's row tracks */
  grid-template-rows: subgrid;
  gap: 0.5rem;
}

/* Now .card > h3, .card > p, .card > button
   all align across cards automatically */

/* Masonry — when it ships */
.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  grid-template-rows: masonry;
  gap: 1rem;
}

/* That's it. Items pack into the shortest column.
   No JavaScript. No measuring heights.
   Just grid doing what grid does best. */

.parent {
  display: flex;
  justify-content: center;
  align-items: center;
}

.child {
  width: 200px;
  height: 200px;
  background: coral;
}

/* Common misconception */
.item-a { flex-grow: 1; } /* NOT 25% of container */
.item-b { flex-grow: 3; } /* NOT 75% of container */

/* What actually happens:
   1. Each item starts at its content/basis size
   2. LEFTOVER space is divided 1:3
   3. Final sizes depend on content + share of remainder */

/* If you want actual ratios, use flex-basis */
.item-a { flex: 1 1 0%; } /* NOW it's 25% */
.item-b { flex: 3 1 0%; } /* NOW it's 75% */
/* flex-basis: 0% means "start from zero,
   so ALL space is leftover" */

/* align-items: each item within its row */
.flex-container {
  display: flex;
  flex-wrap: wrap;
  align-items: center; /* each item centered in ITS row */
