grid-template-columns: fit-content(200px) 1fr;
/* Sidebar: as wide as content, but max 200px.
   Main: everything else. */

.button {
  /* Resolution chain:
     1. Component token (most specific)
     2. Semantic token (design system default)
     3. Hardcoded fallback (safety net) */
  background: var(--button-bg, var(--color-primary, #3b82f6));
  color: var(--button-text, var(--color-on-primary, white));
  padding: var(--button-padding, var(--spacing-md, 0.75rem 1.5rem));
}

/* Override at any level */
.card .button {
  --button-bg: var(--color-secondary); /* component level */
}

[data-theme="dark"] {
  --color-primary: #60a5fa; /* semantic level */
}

/* Transition — A to B, triggered by state change */
.button {
  background: blue;
  transition: background 0.2s ease;
}
.button:hover {
  background: darkblue;
  /* Smoothly goes from blue → darkblue */
}

/* Animation — multi-step, runs on its own */
@keyframes pulse {
  0% { transform: scale(1); }
  50% { transform: scale(1.05); }
  100% { transform: scale(1); }
}
.badge {
  animation: pulse 2s ease-in-out infinite;
  /* Loops forever, no trigger needed */
}

/* Style Dictionary config */
{
  "source": ["tokens/**/*.json"],
  "platforms": {
    "css": {
      "transformGroup": "css",
      "files": [{
        "destination": "tokens.css",
        "format": "css/variables"
      }]
    },
    "tailwind": {
      "transformGroup": "css",
      "files": [{
        "destination": "theme.css",
        "format": "css/tailwind-theme"
      }]
    }
  }
}

/* Output: tokens.css */
:root {
  --color-primary: #3b82f6;
  --spacing-md: 1rem;
  --radius-lg: 0.75rem;
}
